	"golang.org/x/net/html"
)

type PreviewRequest struct {
	URL string `json:"url"`
}

type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	parsedURL, err := url.Parse(req.URL)
	if err != nil || !strings.HasPrefix(parsedURL.Scheme, "http") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL"})
	}

	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusServiceUnavailable, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL returned non-200 status"})
	}

	content, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response"})
	}

	title, description := parseHTML(string(content))
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func parseHTML(content string) (title, description string) {
	doc, err := html.Parse(strings.NewReader(content))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			case "meta":
				var isDesc bool
				var content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDesc = true
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDesc {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description
}

