package main

import (
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
)

type requestData struct {
	URL string `json:"url"`
}

type previewData struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req requestData
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request format"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	parsedURL, err := url.Parse(req.URL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusServiceUnavailable, map[string]string{"error": fmt.Sprintf("Failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("HTTP error: %s", resp.Status)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	htmlContent := string(body)
	title := extractTitle(htmlContent)
	description := extractMetaDescription(htmlContent)

	return ctx.JSON(http.StatusOK, previewData{
		Title:       title,
		Description: description,
	})
}

func extractTitle(html string) string {
	start := strings.Index(html, "<title>")
	if start == -1 {
		return ""
	}
	start += len("<title>")
	end := strings.Index(html[start:], "</title>")
	if end == -1 {
		return ""
	}
	return html[start : start+end]
}

func extractMetaDescription(html string) string {
	start := strings.Index(html, "name=\"description\"")
	if start == -1 {
		return ""
	}
	contentStart := strings.Index(html[start:], "content=\"")
	if contentStart == -1 {
		return ""
	}
	start += contentStart + len("content=\"")
	end := strings.Index(html[start:], "\"")
	if end == -1 {
		return ""
	}
	return html[start : start+end]
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

