	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(c echo.Context) error {
	var req request
	if err := json.NewDecoder(c.Request().Body).Decode(&req); err != nil {
		return c.JSON(http.StatusBadRequest, echo.Map{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, echo.Map{"error": "URL is required"})
	}

	if !strings.HasPrefix(req.URL, "http://") && !strings.HasPrefix(req.URL, "https://") {
		return c.JSON(http.StatusBadRequest, echo.Map{"error": "Invalid URL scheme"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		if errors.Is(err, context.DeadlineExceeded) {
			return c.JSON(http.StatusRequestTimeout, echo.Map{"error": "Request timeout"})
		}
		return c.JSON(http.StatusInternalServerError, echo.Map{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusBadGateway, echo.Map{"error": "Upstream server error"})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, echo.Map{"error": "Failed to read response body"})
	}

	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return c.JSON(http.StatusInternalServerError, echo.Map{"error": "Failed to parse HTML"})
	}

	preview := response{}
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && preview.Title == "" {
				if n.FirstChild != nil {
					preview.Title = n.FirstChild.Data
				}
			} else if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && preview.Description == "" {
					preview.Description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return c.JSON(http.StatusOK, preview)
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

