					}
					if attr.Key == "content" {
						desc = attr.Val
					}
				}
				if isDesc {
					description = desc
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

