	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusServiceUnavailable, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusServiceUnavailable, map[string]string{"error": "URL returned non-OK status"})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractMetadata(string(body))
