	"time"

	"github.com/labstack/echo/v4"
)

type previewRequest struct {
	URL string `json:"url"`
}

type previewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req previewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request format"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	client := http.Client{Timeout: 3 * time.Second}
	resp, err := client.Get(req.URL)
	if err != nil {
		if errors.Is(err, context.DeadlineExceeded) {
			return ctx.JSON(http.StatusRequestTimeout, map[string]string{"error": "request timed out"})
		}
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL: " + resp.Status})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to read response body"})
	}

	content := string(body)
	title := extractTitle(content)
	description := extractMetaDescription(content)

	return ctx.JSON(http.StatusOK, previewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitle(content string) string {
	titleStart := strings.Index(content, "<title>")
	if titleStart == -1 {
		return ""
	}
	titleStart += len("<title>")
	titleEnd := strings.Index(content[titleStart:], "</title>")
	if titleEnd == -1 {
		return ""
	}
	return strings.TrimSpace(content[titleStart : titleStart+titleEnd])
}

func extractMetaDescription(content string) string {
	descStart := strings.Index(content, `name="description"`)
	if descStart == -1 {
		return ""
	}
	contentStart := strings.Index(content[descStart:], `content="`)
	if contentStart == -1 {
		return ""
	}
	contentStart += descStart + len(`content="`)
	contentEnd := strings.Index(content[contentStart:], `"`)
	if contentEnd == -1 {
		return ""
	}
	return strings.TrimSpace(content[contentStart : contentStart+contentEnd])
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

