package main

import (
	"bytes"
	"encoding/json"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request struct for incoming JSON
type urlRequest struct {
	URL string `json:"url"`
}

// Response struct for preview data
type previewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	// Parse request body
	var req urlRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request"})
	}

	// Validate URL
	parsedURL, err := url.ParseRequestURI(req.URL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid URL"})
	}

	// Create HTTP client with timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch URL content
	resp, err := client.Get(parsedURL.String())
	if err != nil {
		return ctx.JSON(http.StatusServiceUnavailable, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Read response body
	bodyBytes, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to read response"})
	}
	bodyReader := bytes.NewReader(bodyBytes)

	// Parse HTML
	doc, err := html.Parse(bodyReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse HTML"})
	}

	// Extract metadata
	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			case "meta":
				desc := ""
				isDesc := false
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
						isDesc = true
					}
					if attr.Key == "content" {
						desc = attr.Val
					}
				}
				if isDesc && desc != "" {
					description = desc
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	// Return response
	return ctx.JSON(http.StatusOK, previewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

