	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusServiceUnavailable, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if !strings.Contains(resp.Header.Get("Content-Type"), "text/html") {
		return ctx.JSON(http.StatusUnsupportedMediaType, map[string]string{"error": "URL content is not HTML"})
	}

	doc, err := html.Parse(resp.Body)
