	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

type request struct {
	URL string `json:"url"`
}

type response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(c echo.Context) error {
	var req request
	if err := json.NewDecoder(c.Request().Body).Decode(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}
	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Get(req.URL)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	title, description := extractMetadata(resp.Body)
	return c.JSON(http.StatusOK, response{
		Title:       title,
		Description: description,
	})
}

func extractMetadata(r io.Reader) (title, description string) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil && title == "" {
				title = n.FirstChild.Data
			} else if n.Data == "meta" {
				var isDescription bool
				var content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDescription = true
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDescription && description == "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)
	return
}

