package main

import (
	"errors"
	"fmt"
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

type previewRequest struct {
	URL string `json:"url"`
}

type previewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

func FetchURLPreview(ctx echo.Context) error {
	var req previewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		if errors.Is(err, context.DeadlineExceeded) {
			return ctx.JSON(http.StatusRequestTimeout, map[string]string{"error": "request timed out"})
		}
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, 
			map[string]string{"error": fmt.Sprintf("URL returned status: %d", resp.StatusCode)})
	}

	title, description, err := extractMetadata(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse HTML"})
	}

	return ctx.JSON(http.StatusOK, previewResponse{
		Title:       title,
		Description: description,
	})
}

func extractMetadata(r io.Reader) (string, string, error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			case "meta":
				desc := ""
				isDesc := false
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
						isDesc = true
					}
					if attr.Key == "content" {
						desc = attr.Val
					}
				}
				if isDesc && desc != "" {
					description = desc
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description, nil
}

