package main

import (
	"encoding/json"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

type requestData struct {
	URL string `json:"url"`
}

type previewData struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func extractPreview(doc *html.Node) (title, description string) {
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			} else if n.Data == "meta" {
				isDescription := false
				content := ""
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
						isDescription = true
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDescription {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)
	return
}

func FetchURLPreview(ctx echo.Context) error {
	var req requestData
	if err := json.NewDecoder(ctx.Request().Body).Decode(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid JSON"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	parsedURL, err := url.Parse(req.URL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid url"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}
	resp, err := client.Get(req.URL)
	if err != nil {
		if err, ok := err.(interface{ Timeout() bool }); ok && err.Timeout() {
			return ctx.JSON(http.StatusRequestTimeout, map[string]string{"error": "request timeout"})
		}
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch url"})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "url returned non-2xx status"})
	}

	doc, err := html.Parse(io.LimitReader(resp.Body, 10<<20)) // Limit to 10MB
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse html"})
	}

	title, description := extractPreview(doc)
	preview := previewData{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	}

	return ctx.JSON(http.StatusOK, preview)
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

